import importlib.util, re, random; spec = importlib.util.spec_from_file_location('m', '/tmp/eval_branchless/branchless.py'); mod = importlib.util.module_from_spec(spec); spec.loader.exec_module(mod); src = open('/tmp/eval_branchless/branchless.py').read(); body = src; 
import ast as _ast
tree = _ast.parse(src)
for node in _ast.walk(tree):
    assert not isinstance(node, (_ast.If, _ast.IfExp, _ast.For, _ast.While)), f'forbidden control flow: {type(node).__name__}'
    if isinstance(node, _ast.Compare):
        for op in node.ops:
            assert not isinstance(op, (_ast.Lt, _ast.Gt, _ast.LtE, _ast.GtE, _ast.Eq, _ast.NotEq)), f'forbidden comparison op'
    if isinstance(node, _ast.BoolOp):
        raise AssertionError('and/or short-circuit forbidden')
    if isinstance(node, _ast.Call) and isinstance(node.func, _ast.Name) and node.func.id in {'min','max','sorted','abs'}:
        raise AssertionError(f'forbidden call: {node.func.id}')
f = mod.min3_branchless
for a, b, c in [(1,2,3),(3,2,1),(2,1,3),(5,5,5),(-1,0,1),(-10,-5,-20),(100,50,75)]:
    assert f(a,b,c) == min(a,b,c), f'min3({a},{b},{c}) got {f(a,b,c)}'
random.seed(0)
for _ in range(200):
    a,b,c = random.randint(-1000,1000), random.randint(-1000,1000), random.randint(-1000,1000)
    assert f(a,b,c) == min(a,b,c), f'random fail at ({a},{b},{c})'
print('OK')
